#include <iostream>
#include <utility>
class Buffer {
    int* m_data{};
    static inline int s_moves{0};
public:
    Buffer() = default;
    Buffer(int value): m_data{ new int{value} } {}
    Buffer(Buffer&& src) noexcept : m_data{src.m_data}{ ++s_moves; src.m_data=nullptr; }
    Buffer& operator=(Buffer&& src) noexcept {
        if(this!=&src){ ++s_moves; delete m_data; m_data=src.m_data; src.m_data=nullptr; }
        return *this;
    }
    ~Buffer(){ delete m_data; }
    Buffer(const Buffer&)=delete;
    Buffer& operator=(const Buffer&)=delete;
    int value() const { return m_data ? *m_data : 0; }
    static int moves(){ return s_moves; }
};
void swapBuffers(Buffer& a, Buffer& b){
    Buffer temp{ std::move(a) };
    a = std::move(b);
    b = std::move(temp);
}
int main(){
    int va{}, vb{}, k{};
    std::cin >> va >> vb >> k;
    Buffer a{ va }; Buffer b{ vb };
    for(int i=0;i<k;++i){
        swapBuffers(a,b);
        std::cout << a.value() << ' ' << b.value() << '\n';
    }
    std::cout << "moves: " << Buffer::moves() << '\n';
    return 0;
}
